#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 250000
#define MAX_Q 50000
#define MAX_SUBSTRINGS 1000000

// Define the structure for a tree node
typedef struct Node {
    int id;
    char value;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int id, char value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->id = id;
    node->value = value;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to generate all possible substrings for a given node
void generateSubstrings(Node* node, char** substrings, int* numSubstrings) {
    // Generate substrings for the current node
    char substring[2];
    substring[0] = node->value;
    substring[1] = '\0';
    substrings[*numSubstrings] = (char*)malloc(strlen(substring) + 1);
    strcpy(substrings[*numSubstrings], substring);
    (*numSubstrings)++;

    // Recursively generate substrings for child nodes
    for (int i = 0; i < node->numChildren; i++) {
        generateSubstrings(node->children[i], substrings, numSubstrings);
    }
}

// Function to sort substrings based on custom alphabetical order
void sortSubstrings(char** substrings, int numSubstrings, char* order) {
    // Implement custom sorting algorithm based on the provided order
    for (int i = 0; i < numSubstrings - 1; i++) {
        for (int j = i + 1; j < numSubstrings; j++) {
            int k = 0;
            while (k < strlen(substrings[i]) && k < strlen(substrings[j])) {
                if (order[strings[i][k] - 'a'] < order[strings[j][k] - 'a']) break;
                if (order[strings[i][k] - 'a'] > order[strings[j][k] - 'a']) {
                    char* temp = substrings[i];
                    substrings[i] = substrings[j];
                    substrings[j] = temp;
                    break;
                }
                k++;
            }
            if (k == strlen(substrings[i])) {
                if (strlen(substrings[i]) < strlen(substrings[j])) break;
                else {
                    char* temp = substrings[i];
                    substrings[i] = substrings[j];
                    substrings[j] = temp;
                }
            }
        }
    }
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);

    // Read the tree string
    char treeString[N + 1];
    scanf("%s", treeString);

    // Create the tree nodes
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i, treeString[i]);
    }

    // Read the edges and construct the tree
    for (int i = 0; i < N - 1; i++) {
        int Xi, Yi;
        scanf("%d %d", &Xi, &Yi);
        addChild(nodes[Xi - 1], nodes[Yi - 1]);
    }

    // Generate all possible substrings
    char* substrings[MAX_SUBSTRINGS];
    int numSubstrings = 0;
    generateSubstrings(nodes[0], substrings, &numSubstrings);

    // Process queries
    for (int i = 0; i < Q; i++) {
        char order[27];
        int Ki;
        scanf("%s %d", order, &Ki);

        // Sort substrings based on custom alphabetical order
        sortSubstrings(substrings, numSubstrings, order);

        // Output the Ki-th substring
        if (Ki <= numSubstrings) {
            printf("%s\n", substrings[Ki - 1]);
        } else {
            printf("-1\n");
        }
    }

    return 0;
}

