#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

// Define the structure for a tree node
struct Node {
    int id;
    char value;
    vector<Node*> children;
};

// Function to create a new tree node
Node* createNode(int id, char value) {
    Node* node = new Node;
    node->id = id;
    node->value = value;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->children.push_back(child);
}

// Function to generate all possible substrings for a given node
void generateSubstrings(Node* node, vector<string>& substrings) {
    // Generate substrings for the current node
    string substring(1, node->value);
    substrings.push_back(substring);

    // Recursively generate substrings for child nodes
    for (Node* child : node->children) {
        generateSubstrings(child, substrings);
    }
}

// Function to sort substrings based on custom alphabetical order
void sortSubstrings(vector<string>& substrings, string order) {
    // Implement custom sorting algorithm based on the provided order
    sort(substrings.begin(), substrings.end(), [&](const string& a, const string& b) {
        for (int i = 0; i < min(a.size(), b.size()); i++) {
            if (order.find(a[i]) < order.find(b[i])) return true;
            if (order.find(a[i]) > order.find(b[i])) return false;
        }
        return a.size() < b.size();
    });
}

int main() {
    int N, Q;
    cin >> N >> Q;

    // Read the tree string
    string treeString;
    cin >> treeString;

    // Create the tree nodes
    Node* nodes[N];
    for (int i = 0; i < N; i++) {
        nodes[i] = createNode(i, treeString[i]);
    }

    // Read the edges and construct the tree
    for (int i = 0; i < N - 1; i++) {
        int Xi, Yi;
        cin >> Xi >> Yi;
        addChild(nodes[Xi - 1], nodes[Yi - 1]);
    }

    // Generate all possible substrings
    vector<string> substrings;
    generateSubstrings(nodes[0], substrings);

    // Process queries
    for (int i = 0; i < Q; i++) {
        string order;
        int Ki;
        cin >> order >> Ki;

        // Sort substrings based on custom alphabetical order
        sortSubstrings(substrings, order);

        // Output the Ki-th substring
        if (Ki <= substrings.size()) {
            cout << substrings[Ki - 1] << endl;
        } else {
            cout << -1 << endl;
        }
    }

    return 0;
}

