import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    // Define the structure for a tree node
    static class Node {
        int id;
        char value;
        ArrayList<Node> children;
        public Node(int id, char value) {
            this.id = id;
            this.value = value;
            children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to generate all possible substrings for a given node
    public static void generateSubstrings(Node node, ArrayList<String> substrings) {
        // Generate substrings for the current node
        String substring = String.valueOf(node.value);
        substrings.add(substring);

        // Recursively generate substrings for child nodes
        for (Node child : node.children) {
            generateSubstrings(child, substrings);
        }
    }

    // Function to sort substrings based on custom alphabetical order
    public static void sortSubstrings(ArrayList<String> substrings, String order) {
        // Implement custom sorting algorithm based on the provided order
        substrings.sort((a, b) -> {
            for (int i = 0; i < Math.min(a.length(), b.length()); i++) {
                if (order.indexOf(a.charAt(i)) < order.indexOf(b.charAt(i))) return -1;
                if (order.indexOf(a.charAt(i)) > order.indexOf(b.charAt(i))) return 1;
            }
            return a.length() - b.length();
        });
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        scanner.nextLine();

        // Read the tree string
        String treeString = scanner.nextLine();

        // Create the tree nodes
        Node[] nodes = new Node[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = new Node(i, treeString.charAt(i));
        }

        // Read the edges and construct the tree
        for (int i = 0; i < N - 1; i++) {
            int Xi = scanner.nextInt();
            int Yi = scanner.nextInt();
            scanner.nextLine();
            addChild(nodes[Xi - 1], nodes[Yi - 1]);
        }

        // Generate all possible substrings
        ArrayList<String> substrings = new ArrayList<>();
        generateSubstrings(nodes[0], substrings);

        // Process queries
        for (int i = 0; i < Q; i++) {
            String order = scanner.nextLine();
            int Ki = scanner.nextInt();
            scanner.nextLine();

            // Sort substrings based on custom alphabetical order
            sortSubstrings(substrings, order);

            // Output the Ki-th substring
            if (Ki <= substrings.size()) {
                System.out.println(substrings.get(Ki - 1));
            } else {
                System.out.println(-1);
            }
        }
    }
}

